#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AvrCoreClass {
    Unknown = 0,
    RC, // AVRrc
    E,  // AVRe
    EP, // AVRe+
    XT, // AVRxt
    XM, // AVRxm
}

#[derive(Debug, Clone)]
pub struct AvrDevice {
    pub name: &'static str,
    pub arch: u8,
    pub core: AvrCoreClass,
    pub flash_bytes: u32,
    pub sram_bytes: u32,
    pub eeprom_bytes: u32,
    pub sram_start: u32,
    pub ram_end: u32,
}

